import{_ as e,o as i,c as s,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Arquitectura interna de InnoDB","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/mysql/08-arquitectura-interna-de-innodb.md","filePath":"bases-de-datos/mysql/08-arquitectura-interna-de-innodb.md","lastUpdated":1782521464000}'),t={name:"bases-de-datos/mysql/08-arquitectura-interna-de-innodb.md"};function r(o,a,l,d,c,p){return i(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="arquitectura-interna-de-innodb" tabindex="-1">Arquitectura interna de InnoDB <a class="header-anchor" href="#arquitectura-interna-de-innodb" aria-label="Permalink to &quot;Arquitectura interna de InnoDB&quot;">​</a></h1><p>InnoDB es el motor de almacenamiento principal de MySQL. Aporta transacciones ACID, claves foraneas, indices B-Tree, bloqueos por fila y recuperacion ante fallos.</p><h2 id="arquitectura-conceptual" tabindex="-1">Arquitectura conceptual <a class="header-anchor" href="#arquitectura-conceptual" aria-label="Permalink to &quot;Arquitectura conceptual&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Q[&quot;SQL layer&quot;] --&gt; I[&quot;InnoDB&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  I --&gt; BP[&quot;Buffer pool&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  I --&gt; LG[&quot;Redo log&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  I --&gt; UN[&quot;Undo logs&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  I --&gt; TS[&quot;Tablespaces&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  BP --&gt; D[&quot;Data pages&quot;]</span></span></code></pre></div><h2 id="sql-layer-y-storage-engine" tabindex="-1">SQL layer y storage engine <a class="header-anchor" href="#sql-layer-y-storage-engine" aria-label="Permalink to &quot;SQL layer y storage engine&quot;">​</a></h2><p>MySQL separa:</p><ul><li>Capa SQL: parser, optimizer, permisos, funciones SQL.</li><li>Motor de almacenamiento: lectura/escritura fisica, indices, transacciones.</li></ul><p>InnoDB es el motor mas habitual para aplicaciones transaccionales.</p><h2 id="buffer-pool" tabindex="-1">Buffer pool <a class="header-anchor" href="#buffer-pool" aria-label="Permalink to &quot;Buffer pool&quot;">​</a></h2><p>El buffer pool cachea paginas de datos e indices en memoria.</p><p>Variable importante:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;innodb_buffer_pool_size&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>En servidores dedicados a MySQL, suele ser una de las configuraciones mas importantes.</p><h2 id="paginas" tabindex="-1">Paginas <a class="header-anchor" href="#paginas" aria-label="Permalink to &quot;Paginas&quot;">​</a></h2><p>InnoDB trabaja con paginas, normalmente de 16 KB. Las filas e indices se almacenan en paginas.</p><p>Esto explica por que los indices y el orden fisico afectan lecturas.</p><h2 id="clustered-index" tabindex="-1">Clustered index <a class="header-anchor" href="#clustered-index" aria-label="Permalink to &quot;Clustered index&quot;">​</a></h2><p>En InnoDB, la primary key es el clustered index. Los datos de la fila viven ordenados por la primary key.</p><p>Si no defines primary key, InnoDB crea una interna. Es mejor definir una explicitamente.</p><h2 id="indices-secundarios" tabindex="-1">Indices secundarios <a class="header-anchor" href="#indices-secundarios" aria-label="Permalink to &quot;Indices secundarios&quot;">​</a></h2><p>Un indice secundario guarda la clave indexada y la primary key de la fila.</p><p>Por eso primary keys enormes aumentan el tamaño de indices secundarios.</p><h2 id="redo-log" tabindex="-1">Redo log <a class="header-anchor" href="#redo-log" aria-label="Permalink to &quot;Redo log&quot;">​</a></h2><p>El redo log permite recuperar cambios confirmados tras fallo.</p><p>Flujo simplificado:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cambio en memoria -&gt; redo log -&gt; flush a datos</span></span></code></pre></div><h2 id="undo-log" tabindex="-1">Undo log <a class="header-anchor" href="#undo-log" aria-label="Permalink to &quot;Undo log&quot;">​</a></h2><p>El undo log permite:</p><ul><li>Rollback.</li><li>Lecturas consistentes mediante MVCC.</li></ul><h2 id="change-buffer" tabindex="-1">Change buffer <a class="header-anchor" href="#change-buffer" aria-label="Permalink to &quot;Change buffer&quot;">​</a></h2><p>InnoDB puede diferir cambios de indices secundarios para optimizar escrituras.</p><p>No suele configurarse a diario, pero ayuda a entender rendimiento de escrituras.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Define primary keys pequenas y estables.</li><li>Usa InnoDB salvo razon clara.</li><li>Dimensiona buffer pool con datos reales.</li><li>Entiende que indices secundarios incluyen la primary key.</li><li>No optimices configuracion sin medir.</li></ul>`,34)])])}const m=e(t,[["render",r]]);export{h as __pageData,m as default};
